import React, { useState, useRef, useEffect } from "react";
import "./App.css";

function App() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const [loading, setLoading] = useState(false);

  const chatEndRef = useRef(null);
  const textareaRef = useRef(null);

  // Auto scroll
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  // Auto expand textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height =
        textareaRef.current.scrollHeight + "px";
    }
  }, [message]);

  const sendMessage = async () => {
    if (!message.trim() || loading) return;

    const userText = message;
    setMessage("");

    const userMsg = { role: "user", text: userText };
    setChat((prev) => [...prev, userMsg]);

    setLoading(true);

    try {
      const res = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: userText })
      });

      const data = await res.json();

      setChat((prev) => [
        ...prev,
        { role: "bot", text: data.answer, sources: data.sources }
      ]);
    } catch (err) {
      setChat((prev) => [
        ...prev,
        { role: "bot", text: "⚠️ Error connecting to server." }
      ]);
    }

    setLoading(false);
  };

  return (
    <div className="app">

      {/* Sidebar */}
      <div className="sidebar">
        <div className="nike-logo">
          <img src="/nike.png" alt="nike" />
        </div>

        <div className="brand">
          <h2>SwooshAI</h2>
          <span>JustAsk</span>
        </div>

        <button className="new-chat">+ New Chat</button>

        <div className="recent">
          <h4>Recent Chats</h4>
          <div className="chat-item">Project overview</div>
          <div className="chat-item">Architecture</div>
        </div>
      </div>

      {/* Main */}
      <div className="main">

        {/* Topbar */}
        <div className="topbar">
          <h3>AI Assistant</h3>

          <div className="right-section">
            <img src="/quadrant.png" alt="quadrant" />
          </div>
        </div>

        {/* Chat Area */}
        <div className="chat-area">
          {chat.map((c, i) => (
            <div key={i} className={`msg ${c.role}`}>
              <div className="bubble">
                {c.text}

                {c.sources && (
                  <div className="sources">
                    {c.sources.map((s, idx) => (
                      <a key={idx} href="#" target="_blank" rel="noreferrer">
                        {s}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}

          {/* 🔥 Loading Indicator */}
          {loading && (
            <div className="msg bot">
              <div className="bubble">Typing...</div>
            </div>
          )}

          <div ref={chatEndRef}></div>
        </div>

        {/* ChatGPT Style Input */}
        <div className="input-box">
          <div className="input-box-inner">

            {/* Mic */}
            <button className="icon-btn">🎤</button>

            {/* Textarea */}
            <textarea
              ref={textareaRef}
              rows="1"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Message SwooshAI..."
              disabled={loading}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage();
                }
              }}
            />

            {/* Attachment */}
            <button className="icon-btn">📎</button>

            {/* Send */}
            <button
              className="icon-btn send"
              onClick={sendMessage}
              disabled={loading}
            >
              ➤
            </button>

          </div>
        </div>

      </div>
    </div>
  );
}

export default App;
